        h("div", { className: "truncate pt-2 text-xs text-pulse-dim" }, "Confidence ", forecast.confidence == null ? "—" : `${Math.round(Number(forecast.confidence) * 100)}%`, " · score ", weighted == null ? "—" : Number(weighted).toFixed(1))
