          h("div", null, h("div", { className: "font-mono text-[10px] uppercase tracking-wide text-pulse-dim" }, "What to do"), h("ul", { className: "mt-2 list-disc pl-4 text-sm text-pulse-muted" }, (c.what_to_do || []).map((x, j) => h("li", { key: j }, x))))
